#include <stdio.h>

int main() {
  // Break: find first even number
  for (int i = 1; i <= 10; i++) {
    if (i == 6) {
      break;
    }
    printf("%d ", i);
  }
  printf("\n");
  // Continue: skip odd numbers
  for (int i = 1; i <= 10; i++) {
    if (i % 2 != 0) {
      continue;
    }
    printf("%d ", i);
  }
  printf("\n");
  return 0;
}
